mapper.select:
/* selectShippingOrder */ SELECT ROW_NUMBER() OVER(ORDER BY OI.OUTBOIT) AS ROWNUM , MW.WHNAMLC, OH.OUTBOKY , CONCAT(DATE_FORMAT(OH.OBODATE,'%Y-%m-%d'), DATE_FORMAT(STR_TO_DATE(OH.OBOTIME,'%H%i%s'),'%H:%i:%s')) AS OBODATE , MV.VHCFNAM, OI.SKUMKEY, CONCAT(MA.AREANAM, ' ', ML1.LOCANAM, ' ', OI.FRLAYER, '단') AS SKARLOC , ML2.LOCANAM AS SHLOCNM, ME.EQUINAM AS EQUINAM, OI.SKUTHIC, OI.SKUWIDT , OI.SKULENG, OI.SKUWEIG, MG.GRPKYNM AS GRPKYNM , IF((OI.OWNERKY IS NULL OR TRIM(OI.OWNERKY ) = ''), OI.OWNRNAM, MC.CUNAMLC) AS CUNAMLC , OI.DEMODNM, OI.DEMDADR FROM ${userData.schema}.OOUBIT OI INNER JOIN ${userData.schema}.OOUBHD OH ON OH.OUTBOKY = OI.OUTBOKY AND OH.WAREKEY = OI.WAREKEY INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = OI.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.commonSchema}.MVHCMA MV ON MV.VOWNKEY = OH.VOWNKEY AND MV.VEHICKY = OH.VEHICKY AND MV.VHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = OI.WAREKEY AND MA.AREAKEY = OI.FRAREKY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = OI.WAREKEY AND ML1.AREAKEY = OI.FRAREKY AND ML1.LOCAKEY = OI.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = OI.WAREKEY AND ML2.AREAKEY = OI.FRAREKY AND ML2.LOCAKEY = OI.SHLOCKY AND ML2.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA ME ON OI.EQUIPKY = ME.EQUIPKY AND ME.EQUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MG ON MG.SKUGRKY = OI.SKUGRKY AND MG.GRUSEYN = 'Y' LEFT JOIN ${userData.schema}.MCUSMA MC ON MC.CUSTKEY = OI.OWNERKY AND MC.CUDELYN = 'Y'
AND OH.OUTBOKY = #{param.outboky}
AND OI.WAREKEY = #{param.warekey}
GROUP BY MW.WHNAMLC, OH.OUTBOKY, OH.OBODATE, OH.OBOTIME , MV.VHCFNAM, OI.SKUMKEY, MA.AREANAM, ML1.LOCANAM , OI.FRLAYER, ML2.LOCANAM, ME.EQUINAM, OI.SKUTHIC , OI.SKUWIDT, OI.SKULENG, OI.SKUWEIG, MG.GRPKYNM , OI.OWNERKY, OI.OWNRNAM, MC.CUNAMLC, OI.DESTMOD , OI.DEMODNM ORDER BY ROWNUM

/* selectShippingOrderParam */
SELECT SUM(OI.RGITQTY) AS QUANCNT, SUM(OI.GROSSWG) AS WEIGSUM
FROM ${userData.schema}.OOUBIT OI


    	AND OI.OUTBOKY = #{param.outboky}


    	AND OI.WAREKEY = #{param.warekey}

/* selectOmPrintCnt */
SELECT COUNT(PRINTSQ) AS printcount
FROM ${userData.schema}.SPRTHI
WHERE WAREKEY = #{param.warekey}
AND DOCTYPE = #{param.doctype}
AND PROGRID = #{param.type}

	AND OUTBOKY = #{param.outboky}


	AND SHPDCKY = #{param.shpdcky}

mapper.insert:
/* insertOmPrintLog */
INSERT INTO ${userData.schema}.SPRTHI(
	 PRINTSQ, WAREKEY, DOCCATE, DOCTYPE, PROGRID
	 , OUTBOKY, SHPDCKY, PRTDATE, PRTTIME, PRTUSER
	 , CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER
)VALUES(
	   #{saveData.printsq}, #{saveData.warekey}, #{saveData.doccate}
	 , #{saveData.doctype}, #{saveData.type}

	 	, #{saveData.outboky}, ''


	 	, '', #{saveData.shpdcky}

	 , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	 , to_char(NOW() ,'YYYYMMDD'), to_char(NOW()  ,'hh24miss'), #{userData.useract}
	 , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
)
